  1→/**
  2→ * ContactRepository - CRUD operations for Contact model
  3→ *
  4→ * Provides typed methods for Contact queries with soft-delete support.
  5→ * All errors propagate to caller for handling at API layer.
  6→ */
  7→
  8→import { prisma } from './prisma';
  9→import type {
 10→  Contact,
 11→  Prisma,
 12→} from '@prisma/client';
 13→import { randomUUID } from 'node:crypto';
 14→
 15→/**
 16→ * Contact creation input type
 17→ */
 18→export type ContactCreateInput = Prisma.ContactCreateInput;
 19→
 20→/**
 21→ * Contact update input type
 22→ */
 23→export type ContactUpdateInput = Prisma.ContactUpdateInput;
 24→
 25→/**
 26→ * Contact findMany params type
 27→ */
 28→export type ContactFindManyParams = {
 29→  where?: Prisma.ContactWhereInput;
 30→  orderBy?: Prisma.ContactOrderByWithRelationInput;
 31→  skip?: number;
 32→  take?: number;
 33→  include?: Prisma.ContactInclude;
 34→};
 35→
 36→/**
 37→ * Repository for Contact CRUD operations
 38→ */
 39→export class ContactRepository {
 40→  /**
 41→   * Find many contacts with optional filtering
 42→   * Automatically filters out soft-deleted records
 43→   */
 44→  async findMany(params?: ContactFindManyParams): Promise<Contact[]> {
 45→    const { where, ...rest } = params ?? {};
 46→
 47→    return prisma.contact.findMany({
 48→      ...rest,
 49→      where: {
 50→        ...where,
 51→        deletedAt: null, // Always exclude soft-deleted
 52→      },
 53→    });
 54→  }
 55→
 56→  /**
 57→   * Find a single contact by ID
 58→   * Returns null if not found or soft-deleted
 59→   */
 60→  async findUnique(
 61→    id: string,
 62→    include?: Prisma.ContactInclude
 63→  ): Promise<Contact | null> {
 64→    return prisma.contact.findFirst({
 65→      where: { id, deletedAt: null },
 66→      include,
 67→    });
 68→  }
 69→
 70→  /**
 71→   * Find a single contact by unique fields (email, phone, inn)
 72→   * Returns null if not found or soft-deleted
 73→   */
 74→  async findByEmail(email: string): Promise<Contact | null> {
 75→    return prisma.contact.findFirst({
 76→      where: { email, deletedAt: null },
 77→    });
 78→  }
 79→
 80→  async findByPhone(phone: string): Promise<Contact | null> {
 81→    return prisma.contact.findFirst({
 82→      where: { phone, deletedAt: null },
 83→    });
 84→  }
 85→
 86→  async findByInn(inn: string): Promise<Contact | null> {
 87→    return prisma.contact.findFirst({
 88→      where: { inn, deletedAt: null },
 89→    });
 90→  }
 91→
 92→  /**
 93→   * Create a new contact
 94→   * Generates UUID and updatedAt if not provided (schema requires these fields)
 95→   * Note: createdAt has @default(now()) in schema
 96→   */
 97→  async create(data: ContactCreateInput): Promise<Contact> {
 98→    return prisma.contact.create({
 99→      data: {
100→        ...data,
101→        id: data.id ?? randomUUID(),
102→        updatedAt: data.updatedAt ?? new Date(),
103→      },
104→    });
105→  }
106→
107→  /**
108→   * Update an existing contact
109→   * Throws RecordNotFound if contact doesn't exist or is soft-deleted
110→   */
111→  async update(
112→    id: string,
113→    data: ContactUpdateInput
114→  ): Promise<Contact> {
115→    // Verify contact exists and not deleted
116→    const existing = await this.findUnique(id);
117→    if (!existing) {
118→      throw new Error(`Contact with id ${id} not found`);
119→    }
120→
121→    return prisma.contact.update({
122→      where: { id },
123→      data,
124→    });
125→  }
126→
127→  /**
128→   * Soft delete a contact by setting deletedAt timestamp
129→   * Does NOT actually delete the record from database
130→   */
131→  async softDelete(id: string): Promise<Contact> {
132→    // Verify contact exists and not already deleted
133→    const existing = await this.findUnique(id);
134→    if (!existing) {
135→      throw new Error(`Contact with id ${id} not found`);
136→    }
137→
138→    return prisma.contact.update({
139→      where: { id },
140→      data: { deletedAt: new Date() },
141→    });
142→  }
143→
144→  /**
145→   * Count contacts matching criteria (excluding soft-deleted)
146→   */
147→  async count(where?: Prisma.ContactWhereInput): Promise<number> {
148→    return prisma.contact.count({
149→      where: {
150→        ...where,
151→        deletedAt: null,
152→      },
153→    });
154→  }
155→
156→  /**
157→   * Check if a contact exists by email (excluding soft-deleted)
158→   */
159→  async existsByEmail(email: string): Promise<boolean> {
160→    const count = await prisma.contact.count({
161→      where: { email, deletedAt: null },
162→    });
163→    return count > 0;
164→  }
165→
166→  /**
167→   * Check if a contact exists by phone (excluding soft-deleted)
168→   */
169→  async existsByPhone(phone: string): Promise<boolean> {
170→    const count = await prisma.contact.count({
171→      where: { phone, deletedAt: null },
172→    });
173→    return count > 0;
174→  }
175→}
176→
177→/**
178→ * Singleton instance for use across the application
179→ */
180→export const contacts = new ContactRepository();
181→
182→export default contacts;
